// SecretsStore Durable Object — thin SQL proxy.
// Owns the SQLite database and migrations. Exposes a single executeSql()
// RPC method so the worker can run queries via drizzle-orm/sqlite-proxy.
// All business logic (auth, CRUD, encryption) lives in the worker, not here.

import { DurableObject } from 'cloudflare:workers'
import * as durable from 'drizzle-orm/durable-sqlite'
import * as migrator from 'drizzle-orm/durable-sqlite/migrator'
// @ts-expect-error — migrations.js is generated by drizzle-kit
import migrations from '../../db/drizzle-app/migrations.js'
import * as schema from 'db/src/app-schema.ts'

export class SecretsStore extends DurableObject<Env> {
  db: durable.DrizzleSqliteDODatabase<typeof schema, typeof schema.relations>

  constructor(ctx: DurableObjectState, env: Env) {
    super(ctx, env)
    this.db = durable.drizzle(ctx.storage, { schema, relations: schema.relations })
    ctx.blockConcurrencyWhile(async () => {
      await migrator.migrate(this.db, migrations)
    })
  }

  // RPC: return the IATA airport code of the colo this DO runs in.
  // Fetches https://cloudflare.com/cdn-cgi/trace which egresses from the DO's
  // own data center. Result is cached in DO KV storage permanently — DOs
  // never move after creation, so the colo is constant.
  async getColo(): Promise<string> {
    const cached = await this.ctx.storage.get<string>('_colo')
    if (cached) return cached

    const res = await fetch('https://cloudflare.com/cdn-cgi/trace')
    const text = await res.text()
    const colo = text.match(/colo=(\w+)/)?.[1] ?? 'unknown'

    await this.ctx.storage.put('_colo', colo)
    return colo
  }

  // RPC: execute a SQL query on the DO's SQLite database.
  // Called by the worker's drizzle-orm/sqlite-proxy callback.
  // method is 'all' | 'get' | 'run' | 'values'
  async executeSql(sql: string, params: unknown[], method: string) {
    const stmt = this.ctx.storage.sql.exec(sql, ...params)
    const columnNames = stmt.columnNames
    const rawRows = stmt.toArray()

    if (method === 'get') {
      const row = rawRows[0]
      if (!row) return { rows: null }
      // Return as array of values in column order
      return { rows: columnNames.map((col) => (row as Record<string, unknown>)[col]) }
    }

    // For 'all', 'values', 'run' — return array of row arrays
    const rows = rawRows.map((row) =>
      columnNames.map((col) => (row as Record<string, unknown>)[col]),
    )
    return { rows }
  }
}
